prompt:
        당신은 프랜차이즈 데이터 분석 라우터입니다.
        사용자의 질문을 분석하여, 다음 데이터베이스 스키마 중 어떤 테이블을 조회해야 할지 결정하세요.

        [사용자 질문]
        test

        [데이터베이스 스키마 정의]
        {
  "raw_daily_store_item": {
    "description": "일별 매장 상품별 매출. 모든 컬럼은 text 타입. 수치 집계: CAST(sale_qty AS NUMERIC). 날짜 필터: sale_dt >= '20260401' 처럼 반드시 따옴표 있는 문자열 리터럴 사용(숫자 리터럴 금지)",
    "columns": [
      "sale_dt(매출일자, text YYYYMMDD, 예: '20260415')",
      "masked_stor_cd(매장코드, text)",
      "item_cd(상품코드, text)",
      "item_nm(상품명, text)",
      "sale_qty(판매수량, text→CAST AS NUMERIC)",
      "sale_amt(매출금액, text→CAST AS NUMERIC)",
      "dc_amt(할인금액, text→CAST AS NUMERIC)"
    ]
  },
  "raw_daily_store_pay_way": {
    "description": "일별 매장 결제수단(채널)별 매출. 모든 컬럼은 text 타입",
    "columns": [
      "sale_dt(매출일자, text)",
      "masked_stor_cd(매장코드, text)",
      "pay_way_cd(결제수단코드 01:신용카드 08/09/11:모바일/간편결제, text)",
      "pay_dtl_cd(결제상세코드, text)",
      "pay_amt(결제금액, text→CAST(pay_amt AS NUMERIC)로 집계)"
    ]
  },
  "raw_pay_cd": {
    "description": "결제수단 상세 마스터 (배달의민족, 요기요 등 확인용)",
    "columns": [
      "pay_dc_cd(결제상세코드, text)",
      "pay_dc_nm(결제수단명, text)"
    ]
  },
  "raw_daily_store_item_tmzon": {
    "description": "시간대별 매장 상품 매출 (피크 시간 분석용). 모든 컬럼은 text 타입",
    "columns": [
      "sale_dt(매출일자, text)",
      "masked_stor_cd(매장코드, text)",
      "item_cd(상품코드, text)",
      "tmzon_div(시간대 00~23, text)",
      "sale_qty(판매수량, text→CAST(sale_qty AS NUMERIC)로 집계)",
      "sale_amt(매출금액, text→CAST(sale_amt AS NUMERIC)로 집계)"
    ]
  }
}

        반드시 다음 JSON 형식으로만 응답하세요:
        {
            "intent_category": "channel | campaign | sales_trend | cross_sell",
            "required_tables": ["테이블명1", "테이블명2"]
        }

response:
{
  "sql": "SELECT sale_dt, item_cd, item_nm, CAST(sale_qty AS NUMERIC) AS sale_qty, CAST(sale_amt AS NUMERIC) AS sale_amt FROM raw_daily_store_item WHERE masked_stor_cd = :store_id ORDER BY sale_dt DESC LIMIT 10"
}

