        반드시 다음 JSON 형식으로만 응답하세요:
        {
            "intent_category": "channel | campaign | sales_trend | cross_sell | other",
            "required_tables": ["테이블명1", "테이블명2"]
        }

response:
{
    "sql": "SELECT sale_dt, SUM(CAST(pay_amt AS NUMERIC)) AS delivery_sale_amt FROM raw_daily_store_pay_way JOIN raw_pay_cd ON raw_daily_store_pay_way.pay_dtl_cd = raw_pay_cd.pay_dc_cd WHERE masked_stor_cd = :store_id AND (pay_dc_nm LIKE '%배달%' OR pay_dc_nm LIKE '%배민%' OR pay_dc_nm LIKE '%요기요%' OR pay_dc_nm LIKE '%쿠팡%') GROUP BY sale_dt ORDER BY sale_dt DESC LIMIT 30"
}

